<template><div class="page-container"><el-card><template #header><span>Listing管理</span><el-button type="primary" size="small" style="float:right" @click="handleSync">同步产品</el-button></template><el-form :inline="true"><el-form-item label="站点"><el-select v-model="f.country" clearable><el-option v-for="c in ['US','UK','DE','JP']" :key="c" :label="c" :value="c"/></el-select></el-form-item><el-form-item label="状态"><el-select v-model="f.status" clearable><el-option v-for="s in ['ACTIVE','INACTIVE','DELETED']" :key="s" :label="s" :value="s"/></el-select></el-form-item><el-form-item><el-input v-model="f.search" placeholder="MSKU/ASIN/品名" clearable style="width:200px"/></el-form-item><el-form-item><el-button type="primary" @click="search">查询</el-button></el-form-item></el-form><el-table :data="list" border stripe v-loading="loading"><el-table-column prop="msku" label="MSKU" width="150"/><el-table-column prop="asin" label="ASIN" width="100"/><el-table-column prop="title" label="标题" show-overflow-tooltip/><el-table-column prop="country" label="站点" width="60"/><el-table-column prop="status" label="状态" width="80"/><el-table-column prop="price" label="价格" width="80"/><el-table-column prop="sales_volume" label="销量" width="80"/><el-table-column prop="rating" label="评分" width="80"/><el-table-column prop="synced_at" label="同步时间" width="160"/><el-table-column label="操作" width="150" fixed="right"><template #default="{ row }"><el-button size="small">配对</el-button><el-button size="small" type="warning">调价</el-button></template></el-table-column></el-table><el-pagination v-model:current-page="p.page" layout="total,prev,pager,next" :total="p.total" @current-change="load"/></el-card></div></template>
<script setup>import { ref, reactive, onMounted } from 'vue'; import { amazonListingApi } from '@/api/salesSys'; import { ElMessage } from 'element-plus'
const f = reactive({ country: '', status: '', search: '' }); const list = ref([]); const loading = ref(false); const p = reactive({ page: 1, total: 0 })
async function load() { loading.value = true; try { const data = await amazonListingApi.list({ ...f, page: p.page }); list.value = data?.results || data || []; p.total = data?.count || 0 } catch { } finally { loading.value = false } }
function search() { p.page = 1; load() }
function handleSync() { ElMessage.success('同步任务已提交') }
onMounted(load)
</script>
